var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"벌써 새로운 계약인가요?","JPN":"もう新しい契約ですか？","ENG":"A new contract? Already?","TWN":"這麼快就簽訂新的合約了嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"저희가 거래에서 받기로 했던 건 정식 라이선스까지인 줄 알았는데요.","JPN":"私たちが取引で受けることにしたのは、正式ライセンスまでだと思ったんですが。","ENG":"I thought the official license was the best we could get from you.","TWN":"我以爲我們在交易的是制裁者的正式執照呢。 "},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그런데, 이 계약서에 있는 조건은 저에게만 너무 유리한 내용 아닌가요?","JPN":"ところで、この契約書の条件は私にだけとても有利な内容じゃないですか？","ENG":"By the way, don't you think this contract is unreasonably favorable to me?","TWN":"但是，這個合約中的條件是不是對我太有利了？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"후후, 질문이 불편하셨다면 죄송해요.","JPN":"ふふ、気に障るような質問でしたらごめんなさい。","ENG":"Hah hah, I'm sorry if I made you feel uncomfortable.","TWN":"嘻嘻，如果你覺得我講話太直接的話還請見諒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"이런 제안을 받을 땐 저도 모르게 계산을 먼저 하게 되더라고요.","JPN":"こういう提案を受けるときは、つい色々考えてしまうんです。","ENG":"I can't help but calculate when I receive offers like this.","TWN":"我每次接到新的合約或提案時，不自覺都會先算清楚利益。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"만일에 하나라는 생각으로 사람을 쉽게 믿지 않기로 결심했던 게 엊그제 같은데......","JPN":"万が一ということもありますし、他人を簡単に信用しないと決めたのがまるで昨日のことのようですが……","ENG":"It's still fresh on my mind how I decided not to trust others,","TWN":"為了避免各種意外發生，我曾下定決心不輕易相信任何人，就像在不久前的事情…… "},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"사장님과 얘길 나누고 있으면, 여태 의심해왔던 것들이 바보 같았다는 생각마저 든다니까요.","JPN":"社長と話していると、これまで疑ってきたのがバカみたいに感じられることもあります。","ENG":"but every time I talk to you, I reconsider my decision.","TWN":"能和老闆這樣聊天，會覺得一直以來自己這些充滿疑心的舉動就像個傻瓜一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"뭐, 물론 남을 함부로 믿지 않겠다는 마음은 지금도 변함 없습니다.","JPN":"もちろん、無駄に他人を信用しないという考えは、今も変わりありません。","ENG":"I'm not saying I'm going to let my guard down and start trusting people.","TWN":"嗯，當然現在也不會輕易相信別人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"하지만, 이제 더는 사장님을 남이라고 생각하지 않기로 했으니까요.","JPN":"ですが、これからは社長のことを他人だと思わないことにしました。","ENG":"But at least I no longer consider you one of them.","TWN":"但是，我决定不再把老闆當成別人了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"네? 남이 아니면 뭐냐고요?","JPN":"はい？他人ではなかったら何かって？","ENG":"Pardon? What are you to me, then?","TWN":"嗯？你想問說不是別人，那會是什麼嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그야 언제까지나 사장님은 저의 사장님이죠.","JPN":"それは、いつになっても社長は私の社長ですよ。","ENG":"Well, my boss. That's not going to change.","TWN":"那就是… 老闆將會永遠都是我專屬的老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"저는요. 호칭이란 것 자체는 크게 중요하지 않다고 생각해요. 부르는 이름이 변치 않더라도 그 이름에 담긴 의미는 얼마든지 변할 수 있는 거잖아요?","JPN":"私は、呼称というもの自体は大して重要ではないと思うんです。呼び名は変わらなくても、その名に込められた意味はいくらでも変わるじゃないですか。","ENG":"Titles and honorifics don't matter to me. I may call you the same thing, but the meaning behind it can change anytime, now can't it?","TWN":"我呢，我覺得稱謂的本身並不重要，即使稱呼的名字不變，名字所蘊含的意義也會隨時改變吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_SPORTS","text":{"KOREA":"그럼, 앞으로도 잘 부탁 드립니다. 저의 영원한 사장님?","JPN":"では、これからもよろしくお願いします。私の永遠の社長？","ENG":"So, thank you for hiring me again. My eternal boss.","TWN":"那麼，以後也請多多關照，我永遠的老闆？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};